{
  "sentences": [
    {
      "text": "我在圖書館複習中文句子。",
      "pinyin": "Wǒ zài túshūguǎn fùxí zhōngwén jùzi.",
      "pinyin_numeric": "wo3 zai4 tu2shu1guan3 fu4xi2 zhong1wen2 ju4zi0",
      "translation_en": "I am reviewing Chinese sentences at the library.",
      "translation_ko": "저는 도서관에서 중국어 문장을 복습하고 있어요."
    },
    {
      "text": "他在公司改正錯誤的重點。",
      "pinyin": "Tā zài gōngsī gǎizhèng cuòwù de zhòngdiǎn.",
      "pinyin_numeric": "ta1 zai4 gong1si1 gai3zheng4 cuo4wu4 de0 zhong4dian3",
      "translation_en": "He is correcting the key points of the mistakes at the company.",
      "translation_ko": "그는 회사에서 실수의 핵심을 고치고 있어요."
    },
    {
      "text": "我們在教室再試一次說流利的句子。",
      "pinyin": "Wǒmen zài jiàoshì zài shì yī cì shuō liúlì de jùzi.",
      "pinyin_numeric": "wo3men0 zai4 jiao4shi4 zai4 shi4 yi1 ci4 shuo1 liu2li4 de0 ju4zi0",
      "translation_en": "We are trying again to speak fluent sentences in the classroom.",
      "translation_ko": "우리는 교실에서 다시 한 번 유창한 문장을 말해 보려고 해요."
    },
    {
      "text": "她在咖啡店複習今天的弱點。",
      "pinyin": "Tā zài kāfēidiàn fùxí jīntiān de ruòdiǎn.",
      "pinyin_numeric": "ta1 zai4 ka1fei1dian4 fu4xi2 jin1tian1 de0 ruo4dian3",
      "translation_en": "She is reviewing today's weak points at the coffee shop.",
      "translation_ko": "그녀는 커피숍에서 오늘의 약점을 복습하고 있어요."
    },
    {
      "text": "我們在餐廳改正錯誤的答案。",
      "pinyin": "Wǒmen zài cāntīng gǎizhèng cuòwù de dá'àn.",
      "pinyin_numeric": "wo3men0 zai4 can1ting1 gai3zheng4 cuo4wu4 de0 da2'an4",
      "translation_en": "We are correcting the wrong answers at the restaurant.",
      "translation_ko": "우리는 식당에서 틀린 답을 고치고 있어요."
    },
    {
      "text": "他在公園複習重點和句子。",
      "pinyin": "Tā zài gōngyuán fùxí zhòngdiǎn hé jùzi.",
      "pinyin_numeric": "ta1 zai4 gong1yuan2 fu4xi2 zhong4dian3 he2 ju4zi0",
      "translation_en": "He is reviewing key points and sentences at the park.",
      "translation_ko": "그는 공원에서 핵심과 문장을 복습하고 있어요."
    },
    {
      "text": "我在醫院改正弱點，再試一次。",
      "pinyin": "Wǒ zài yīyuàn gǎizhèng ruòdiǎn, zài shì yī cì.",
      "pinyin_numeric": "wo3 zai4 yi1yuan4 gai3zheng4 ruo4dian3, zai4 shi4 yi1 ci4",
      "translation_en": "I am correcting my weak points at the hospital and trying again.",
      "translation_ko": "저는 병원에서 약점을 고치고 다시 한 번 시도해요."
    },
    {
      "text": "她在學校複習流利的句子和答案。",
      "pinyin": "Tā zài xuéxiào fùxí liúlì de jùzi hé dá'àn.",
      "pinyin_numeric": "ta1 zai4 xue2xiao4 fu4xi2 liu2li4 de0 ju4zi0 he2 da2'an4",
      "translation_en": "She is reviewing fluent sentences and answers at school.",
      "translation_ko": "그녀는 학교에서 유창한 문장과 답을 복습하고 있어요."
    },
    {
      "text": "我們在車站改正錯誤的重點。",
      "pinyin": "Wǒmen zài chēzhàn gǎizhèng cuòwù de zhòngdiǎn.",
      "pinyin_numeric": "wo3men0 zai4 che1zhan4 gai3zheng4 cuo4wu4 de0 zhong4dian3",
      "translation_en": "We are correcting the key points of the mistakes at the station.",
      "translation_ko": "우리는 역에서 실수의 핵심을 고치고 있어요."
    },
    {
      "text": "他在商店複習弱點，再試一次說清楚。",
      "pinyin": "Tā zài shāngdiàn fùxí ruòdiǎn, zài shì yī cì shuō qīngchǔ.",
      "pinyin_numeric": "ta1 zai4 shang1dian4 fu4xi2 ruo4dian3, zai4 shi4 yi1 ci4 shuo1 qing1chu3",
      "translation_en": "He is reviewing his weak points at the store and trying again to speak clearly.",
      "translation_ko": "그는 가게에서 약점을 복습하고 다시 한 번 명확하게 말해 보려고 해요."
    }
  ]
}
